module shift_register (
    input clk,
    input rst_n,
    input en,
    output reg [15:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        q <= 16'b0000000000000000;
    else if (en)
        q <= q >> 1;
end

endmodule
